const FILTER_SECTIONS: SearchDropdownSection[] = [
  {
    options: [
      {
        label: 'All',
        value: 'all',
      },
    ],
  },
  {
    title: 'Category',
    options: [
      {
        label: 'Halves',
        value: 'halves',
      },
      {
        label: 'Thirds',
        value: 'thirds',
