interface EditQuicklinkViewProps {
  quicklink?: QuicklinkEntry;
  onSubmit: (form: QuicklinkFormState) => void;
}

function EditQuicklinkView({ quicklink, onSubmit }: EditQuicklinkViewProps) {
  const [form, setForm] = useState<QuicklinkFormState>(() => {
    if (quicklink) {
      return {
        name: quicklink.name,
        link: quicklink.link,
        type: quicklink.type,
        iconChoice: 'auto',
        application: quicklink.application ?? '',
      };
    }
    return INITIAL_FORM;
  });
  const [errors, setErrors] = useState<
    Partial<Record<keyof QuicklinkFormState, string>>
  >({});

  const handleSubmit = useCallback(() => {
    const newErrors: Partial<Record<keyof QuicklinkFormState, string>> = {};
    if (!form.name.trim()) {
      newErrors.name = 'Name is required';
    }
    if (!form.link.trim()) {
      newErrors.link = 'Link is required';
    }
    setErrors(newErrors);
    if (Object.keys(newErrors).length > 0) return;
    onSubmit(form);
  }, [
    form,
    onSubmit,
  ]);

  useKeyboardShortcut(
    {
      key: 'Enter',
      meta: true,
    },
    handleSubmit,
  );

  return (
    <Form onSubmit={handleSubmit}>
      <FormTextField
        label="Name"
        value={form.name}
        onChange={v =>
          setForm(prev => ({
            ...prev,
            name: v,
          }))
        }
        placeholder="e.g. GitHub Dashboard"
        error={errors.name}
        autoFocus
      />
      <FormTextField
        label="Link"
        value={form.link}
        onChange={v =>
          setForm(prev => ({
            ...prev,
            link: v,
          }))
        }
        placeholder="e.g. https://github.com or ~/Documents"
        description="Use {query} as placeholder for dynamic input"
        error={errors.link}
      />
      <FormDropdown
        label="Type"
        value={form.type}
        onChange={v => {
          if (isQuicklinkType(v)) {
            setForm(prev => ({
              ...prev,
              type: v,
            }));
          }
        }}
        options={TYPE_OPTIONS}
      />
      <FormDropdown
        label="Icon"
        value={form.iconChoice}
        onChange={v => {
          if (isIconChoice(v)) {
            setForm(prev => ({
              ...prev,
              iconChoice: v,
            }));
          }
        }}
        options={ICON_OPTIONS}
      />
      <FormTextField
        label="Open With"
        value={form.application}
        onChange={v =>
          setForm(prev => ({
            ...prev,
            application: v,
          }))
        }
        placeholder="e.g. Safari (optional)"
        description="Application to open the link with"
      />
    </Form>
  );
}

interface QueryInputViewProps {
